import kotlinx.coroutines.awaitAll

fun loadUser(userId: String): String {
  return userId + ":user"
}

fun loadProfile(userId: String): String {
  return userId + ":profile"
}

fun merge(user: String, profile: String): String {
  return user + "|" + profile
}

fun app(userId: String): String {
  val both = awaitAll(loadUser(userId), loadProfile(userId))
  return merge(userId + ":user", userId + ":profile")
}
